"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["939"],{54547(e,o,a){a.r(o),a.d(o,{default:()=>n});var s=a(74848),t=a(47643),r=JSON.parse('{"id":102,"pt":{"title":"Dados do programador","prompt":"I want you to act as a Developer Relations consultant. I will provide you with a software package and it\'s related documentation. Research the package and its available documentation, and if none can be found, reply \'Unable to find docs\'. Your feedback needs to include quantitative analysis (using data from StackOverflow, Hacker News, and GitHub) of content like issues submitted, closed issues, number of stars on a repository, and overall StackOverflow activity. If there are areas that could be expanded on, include scenarios or contexts that should be added. Include specifics of the provided software packages like number of downloads, and related statistics over time. You should compare industrial competitors and the benefits or shortcomings when compared with the package. Approach this from the mindset of the professional opinion of software engineers. Review technical blogs and websites (such as TechCrunch.com or Crunchbase.com) and if data isn\'t available, reply \'No data available\'. Respond in Portuguese. My first request is express [link].","description":"Gostaria que actuasse como consultor de rela\xe7\xf5es com os programadores. Vou fornecer-lhe um pacote de software e a respectiva documenta\xe7\xe3o. Pesquise o pacote e a documenta\xe7\xe3o dispon\xedvel e, se n\xe3o a conseguir encontrar, responda com \\"N\xe3o consigo encontrar a documenta\xe7\xe3o\\". O seu feedback tem de incluir an\xe1lises quantitativas (usando dados do StackOverflow, Hacker News e GitHub) de coisas como problemas submetidos, problemas fechados, n\xfamero de estrelas no reposit\xf3rio e atividade geral no StackOverflow. Se houver \xe1reas que podem ser expandidas, inclua cen\xe1rios ou contextos que devem ser adicionados. Inclua detalhes espec\xedficos sobre os pacotes oferecidos, como o n\xfamero de downloads e estat\xedsticas relevantes ao longo do tempo. Deve comparar os concorrentes do sector e as vantagens ou desvantagens em rela\xe7\xe3o ao pacote. Aborde este assunto com a mentalidade da opini\xe3o profissional de um engenheiro de software. Analise blogues e Web sites de tecnologia (por exemplo, TechCrunch.com ou Crunchbase.com) e responda \\"sem dados\\" se n\xe3o houver dados.","remark":"Agregar dados relevantes no GitHub, StackOverflow e Hacker News relacionados com o projeto. No entanto, este m\xe9todo n\xe3o \xe9 aplic\xe1vel a projectos nacionais e a precis\xe3o estat\xedstica \xe9 m\xe9dia."},"tags":["code"],"website":"https://github.com/f/awesome-chatgpt-prompts#act-as-a-developer-relations-consultant","count":503,"related":[90,218,173],"metaTitle":"Consultor DevRel: An\xe1lise de Pacotes","metaDescription":"Avaliando software? Obtenha an\xe1lise quantitativa do GitHub, StackOverflow e concorrentes.","faq":[{"q":"A IA consegue ver o n\xfamero real de stars no GitHub?","a":"N\xe3o. Ela n\xe3o acessa a internet; todos os n\xfameros s\xe3o \\"impress\xe3o\\" do treino. Para bibliotecas famosas (React, TensorFlow), a intui\xe7\xe3o \xe9 razo\xe1vel; para pequenas, \xe9 chute. Para an\xe1lise real de dados de dev, use libraries.io, GitHub API ou o Hacker News Search."},{"q":"Por que para projetos locais (Vue, Element) o resultado fica impreciso?","a":"A comunidade chinesa concentra atividade em Gitee, Juejin e SegmentFault \u2014 plataformas pouco presentes nos corpora. Em projetos locais, olhe direto os rankings no Gitee e Juejin; os n\xfameros da IA costumam ficar baixos ou errados."}]}');function n(){return(0,s.jsx)(t.A,{prompt:r,currentLanguage:"pt"})}}}]);